extern char *str_dup(const char *s);
if (!s) return str_dup("");
if (max_len <= 0) return str_dup("");
size_t n = strlen(s);
size_t take = (size_t)max_len;
if (take > n) take = n;
char *out = (char *)malloc(take + 1);
if (!out) return NULL;
memcpy(out, s, take);
out[take] = '\0';
return out;
